// 提取查询ID数组
const inputData = $input.all();

console.log('=== 提取查询ID ===');
console.log('输入数据:', inputData);

// 检查输入数据
if (!inputData || !Array.isArray(inputData) || inputData.length === 0) {
  return {
    success: false,
    error: '没有输入数据',
    queryIds: []
  };
}

// 提取所有查询ID
const queryIds = [];
const queryRecords = [];

for (const item of inputData) {
  if (item.json && item.json.queryId) {
    queryIds.push(item.json.queryId);
    queryRecords.push({
      id: item.json.id,
      queryId: item.json.queryId,
      result: item.json.result,
      createdAt: item.json.createdAt,
      updatedAt: item.json.updatedAt
    });
  }
}

console.log('提取到的查询ID:', queryIds);
console.log('查询记录数量:', queryRecords.length);

if (queryIds.length === 0) {
  return {
    success: false,
    error: '没有找到有效的查询ID',
    queryIds: [],
    queryRecords: []
  };
}

return {
  success: true,
  queryIds: queryIds,
  queryRecords: queryRecords,
  totalCount: queryIds.length,
  message: `准备批量处理 ${queryIds.length} 个查询`
};

// 处理批量导出结果
const inputData = $input.all();

console.log('=== 处理批量导出结果 ===');
console.log('输入数据:', inputData);

// 检查输入数据
if (!inputData || !Array.isArray(inputData) || inputData.length === 0) {
  return {
    success: false,
    error: '没有批量导出结果数据'
  };
}

const batchResult = inputData[0].json;
console.log('批量结果:', batchResult);

if (!batchResult.success) {
  return {
    success: false,
    error: batchResult.message || '批量导出失败',
    details: batchResult
  };
}

const { data } = batchResult;
const { results, summary } = data;

// 处理成功和失败的结果
const successfulExports = [];
const failedExports = [];

for (const result of results) {
  if (result.success) {
    successfulExports.push({
      queryId: result.queryId,
      files: result.data.files,
      downloadUrls: result.data.downloadUrls,
      totalRows: result.data.totalRows
    });
  } else {
    failedExports.push({
      queryId: result.queryId,
      error: result.error
    });
  }
}

// 生成汇总消息
let summaryMessage = `📊 批量导出完成\n\n`;
summaryMessage += `✅ 成功: ${data.successful} 个查询\n`;
summaryMessage += `❌ 失败: ${data.failed} 个查询\n`;
summaryMessage += `📁 总文件数: ${summary.totalFiles}\n`;
summaryMessage += `📄 总行数: ${summary.totalRows}\n\n`;

if (successfulExports.length > 0) {
  summaryMessage += `📋 成功导出的文件:\n`;
  for (const export_ of successfulExports) {
    summaryMessage += `- 查询 ${export_.queryId}: ${export_.files.length} 个文件, ${export_.totalRows} 行\n`;
    for (const file of export_.files) {
      summaryMessage += `  📄 ${file.filename} (${file.size} 字节)\n`;
    }
  }
}

if (failedExports.length > 0) {
  summaryMessage += `\n❌ 失败的查询:\n`;
  for (const failed of failedExports) {
    summaryMessage += `- 查询 ${failed.queryId}: ${failed.error}\n`;
  }
}

// 准备Telegram发送数据
const telegramData = {
  message: summaryMessage,
  successfulExports: successfulExports,
  failedExports: failedExports,
  summary: summary,
  totalSuccessful: data.successful,
  totalFailed: data.failed
};

console.log('处理完成:', {
  successful: data.successful,
  failed: data.failed,
  totalFiles: summary.totalFiles,
  totalRows: summary.totalRows
});

return {
  success: true,
  telegramData: telegramData,
  batchResult: batchResult,
  message: `批量处理完成: ${data.successful} 成功, ${data.failed} 失败`
};
